    }

    public async Task<List<InspectionPhoto>> GetPhotosForInspectionAsync(string inspectionId)
    {
        var result = await _js.InvokeAsync<JsonElement>("indexedDbStorage.getItemsByIndex", "photos", "inspectionId", inspectionId);
        return JsonSerializer.Deserialize<List<InspectionPhoto>>(result.GetRawText(), JsonOptions) ?? new();
    }

    public async Task<List<InspectionPhoto>> GetPendingPhotosAsync()
    {
        var result = await _js.InvokeAsync<JsonElement>("indexedDbStorage.getItemsByIndex", "photos", "syncStatus", (int)SyncStatus.Pending);
        return JsonSerializer.Deserialize<List<InspectionPhoto>>(result.GetRawText(), JsonOptions) ?? new();
    }

    public async Task MarkInspectionSyncedAsync(string id)
    {
        var inspection = await GetInspectionAsync(id);
        if (inspection != null)
        {
            inspection.SyncStatus = SyncStatus.Synced;
            await SaveInspectionAsync(inspection);
        }
    }

    public async Task MarkPhotoSyncedAsync(string id)
    {
        var result = await _js.InvokeAsync<JsonElement?>("indexedDbStorage.getItem", "photos", id);
        if (result != null && result.Value.ValueKind != JsonValueKind.Null)
        {
            var photo = JsonSerializer.Deserialize<InspectionPhoto>(result.Value.GetRawText(), JsonOptions);
            if (photo != null)
            {
                photo.SyncStatus = SyncStatus.Synced;
                var obj = JsonSerializer.SerializeToElement(photo, JsonOptions);
                await _js.InvokeVoidAsync("indexedDbStorage.putItem", "photos", obj);
            }
        }
    }
}
