### Step 5: Create SyncService
Create `SiteInspector.Client/Services/SyncService.cs`:
```csharp
using Microsoft.JSInterop;
using System.Net.Http.Json;

namespace SiteInspector.Client.Services;

public class SyncService : IAsyncDisposable
{
    private readonly LocalStorageService _storage;
    private readonly HttpClient _http;
    private readonly IJSRuntime _js;
    private DotNetObjectReference<SyncService>? _dotNetRef;
    private Timer? _syncTimer;

    public bool IsOnline { get; private set; }
    public bool IsSyncing { get; private set; }
    public event Action? OnSyncStatusChanged;

    public SyncService(LocalStorageService storage, HttpClient http, IJSRuntime js)
    {
        _storage = storage;
        _http = http;
        _js = js;
    }

    public async Task InitializeAsync()
    {
        _dotNetRef = DotNetObjectReference.Create(this);
        IsOnline = await _js.InvokeAsync<bool>("connectivityHelper.isOnline");
        await _js.InvokeVoidAsync("connectivityHelper.registerOnlineHandler", _dotNetRef);
        _syncTimer = new Timer(async _ => await TrySyncAsync(), null, TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(30));
    }

    [JSInvokable]
    public async Task OnConnectivityChanged(bool isOnline)
    {
        IsOnline = isOnline;
        OnSyncStatusChanged?.Invoke();
        if (isOnline)
        {
            await TrySyncAsync();
        }
    }

    public async Task TrySyncAsync()
    {
        if (!IsOnline || IsSyncing) return;

        try
        {
            IsSyncing = true;
            OnSyncStatusChanged?.Invoke();

            var pendingInspections = await _storage.GetPendingInspectionsAsync();
            foreach (var inspection in pendingInspections)
            {
                try
                {
                    var items = await _storage.GetChecklistItemsAsync(inspection.Id);
                    var payload = new { inspection, checklistItems = items };
                    var response = await _http.PostAsJsonAsync("/api/sync/inspections", payload);
                    if (response.IsSuccessStatusCode)
                    {
                        await _storage.MarkInspectionSyncedAsync(inspection.Id);
                    }
                }
                catch { /* Will retry on next sync cycle */ }
            }

            var pendingPhotos = await _storage.GetPendingPhotosAsync();
            foreach (var photo in pendingPhotos)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("/api/sync/photos", photo);
                    if (response.IsSuccessStatusCode)
                    {
                        await _storage.MarkPhotoSyncedAsync(photo.Id);
                    }
                }
                catch { /* Will retry on next sync cycle */ }
            }
        }
        catch { /* Sync failed, will retry */ }
        finally
        {
            IsSyncing = false;
            OnSyncStatusChanged?.Invoke();
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_syncTimer != null)
        {
            await _syncTimer.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }
}
