const DB_NAME = 'SiteInspectorDB';
const DB_VERSION = 1;

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const database = e.target.result;
            if (!database.objectStoreNames.contains('sites')) {
                database.createObjectStore('sites', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('inspections')) {
                const store = database.createObjectStore('inspections', { keyPath: 'id' });
                store.createIndex('siteId', 'siteId', { unique: false });
                store.createIndex('syncStatus', 'syncStatus', { unique: false });
            }
            if (!database.objectStoreNames.contains('checklistItems')) {
                const store = database.createObjectStore('checklistItems', { keyPath: 'id' });
                store.createIndex('inspectionId', 'inspectionId', { unique: false });
            }
            if (!database.objectStoreNames.contains('photos')) {
                const store = database.createObjectStore('photos', { keyPath: 'id' });
                store.createIndex('inspectionId', 'inspectionId', { unique: false });
                store.createIndex('syncStatus', 'syncStatus', { unique: false });
            }
        };
        request.onsuccess = (e) => { db = e.target.result; resolve(db); };
        request.onerror = (e) => reject(e.target.error);
    });
}

window.indexedDbStorage = {
    initialize: async function() {
        await openDb();
        return true;
    },

    putItem: async function(storeName, item) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            tx.objectStore(storeName).put(item);
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getItem: async function(storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const request = tx.objectStore(storeName).get(id);
            request.onsuccess = () => resolve(request.result || null);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getAllItems: async function(storeName) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const request = tx.objectStore(storeName).getAll();
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getItemsByIndex: async function(storeName, indexName, value) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const index = tx.objectStore(storeName).index(indexName);
            const request = index.getAll(value);
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    deleteItem: async function(storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            tx.objectStore(storeName).delete(id);
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    }
};

window.connectivityHelper = {
    isOnline: function() {
        return navigator.onLine;
    },
    registerOnlineHandler: function(dotNetRef) {
        window.addEventListener('online', () => dotNetRef.invokeMethodAsync('OnConnectivityChanged', true));
        window.addEventListener('offline', () => dotNetRef.invokeMethodAsync('OnConnectivityChanged', false));
    }
};

using Microsoft.JSInterop;
using SiteInspector.Client.Models;
using System.Text.Json;

namespace SiteInspector.Client.Services;

public class LocalStorageService
{
    private readonly IJSRuntime _js;
    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase
    };

    public LocalStorageService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task InitializeAsync()
    {
        await _js.InvokeVoidAsync("indexedDbStorage.initialize");
    }

    // Sites
    public async Task SaveSiteAsync(ConstructionSite site)
    {
        var obj = JsonSerializer.SerializeToElement(site, JsonOptions);
        await _js.InvokeVoidAsync("indexedDbStorage.putItem", "sites", obj);
    }

    public async Task<List<ConstructionSite>> GetSitesAsync()
    {
        var result = await _js.InvokeAsync<JsonElement>("indexedDbStorage.getAllItems", "sites");
        return JsonSerializer.Deserialize<List<ConstructionSite>>(result.GetRawText(), JsonOptions) ?? new();
    }

    public async Task<ConstructionSite?> GetSiteAsync(string id)
    {
        var result = await _js.InvokeAsync<JsonElement?>("indexedDbStorage.getItem", "sites", id);
        if (result == null || result.Value.ValueKind == JsonValueKind.Null) return null;
        return JsonSerializer.Deserialize<ConstructionSite>(result.Value.GetRawText(), JsonOptions);
    }

    // Inspections
    public async Task SaveInspectionAsync(Inspection inspection)
    {
        var obj = JsonSerializer.SerializeToElement(inspection, JsonOptions);
        await _js.InvokeVoidAsync("indexedDbStorage.putItem", "inspections", obj);
    }

    public async Task<List<Inspection>> GetInspectionsForSiteAsync(string siteId)
    {
        var result = await _js.InvokeAsync<JsonElement>("indexedDbStorage.getItemsByIndex", "inspections", "siteId", siteId);
        return JsonSerializer.Deserialize<List<Inspection>>(result.GetRawText(), JsonOptions) ?? new();
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        var result = await _js.InvokeAsync<JsonElement?>("indexedDbStorage.getItem", "inspections", id);
        if (result == null || result.Value.ValueKind == JsonValueKind.Null) return null;
        return JsonSerializer.Deserialize<Inspection>(result.Value.GetRawText(), JsonOptions);
    }

    public async Task<List<Inspection>> GetPendingInspectionsAsync()
    {
        var result = await _js.InvokeAsync<JsonElement>("indexedDbStorage.getItemsByIndex", "inspections", "syncStatus", (int)SyncStatus.Pending);
        return JsonSerializer.Deserialize<List<Inspection>>(result.GetRawText(), JsonOptions) ?? new();
    }

    // Checklist Items
    public async Task SaveChecklistItemAsync(ChecklistItem item)
    {
        var obj = JsonSerializer.SerializeToElement(item, JsonOptions);
        await _js.InvokeVoidAsync("indexedDbStorage.putItem", "checklistItems", obj);
    }

    public async Task<List<ChecklistItem>> GetChecklistItemsAsync(string inspectionId)
    {
        var result = await _js.InvokeAsync<JsonElement>("indexedDbStorage.getItemsByIndex", "checklistItems", "inspectionId", inspectionId);
        return JsonSerializer.Deserialize<List<ChecklistItem>>(result.GetRawText(), JsonOptions) ?? new();
    }

    // Photos
    public async Task SavePhotoAsync(InspectionPhoto photo)
    {
        var obj = JsonSerializer.SerializeToElement(photo, JsonOptions);
        await _js.InvokeVoidAsync("indexedDbStorage.putItem", "photos", obj);
    }

    public async Task<List<InspectionPhoto>> GetPhotosForInspectionAsync(string inspectionId)
    {
        var result = await _js.InvokeAsync<JsonElement>("indexedDbStorage.getItemsByIndex", "photos", "inspectionId", inspectionId);
        return JsonSerializer.Deserialize<List<InspectionPhoto>>(result.GetRawText(), JsonOptions) ?? new();
    }

    public async Task<List<InspectionPhoto>> GetPendingPhotosAsync()
    {
        var result = await _js.InvokeAsync<JsonElement>("indexedDbStorage.getItemsByIndex", "photos", "syncStatus", (int)SyncStatus.Pending);
        return JsonSerializer.Deserialize<List<InspectionPhoto>>(result.GetRawText(), JsonOptions) ?? new();
    }

    public async Task MarkInspectionSyncedAsync(string id)
    {
        var inspection = await GetInspectionAsync(id);
        if (inspection != null)
        {
            inspection.SyncStatus = SyncStatus.Synced;
            await SaveInspectionAsync(inspection);
        }
    }

    public async Task MarkPhotoSyncedAsync(string id)
    {
        var result = await _js.InvokeAsync<JsonElement?>("indexedDbStorage.getItem", "photos", id);
        if (result != null && result.Value.ValueKind != JsonValueKind.Null)
        {
            var photo = JsonSerializer.Deserialize<InspectionPhoto>(result.Value.GetRawText(), JsonOptions);
            if (photo != null)
            {
                photo.SyncStatus = SyncStatus.Synced;
                var obj = JsonSerializer.SerializeToElement(photo, JsonOptions);
                await _js.InvokeVoidAsync("indexedDbStorage.putItem", "photos", obj);
            }
        }
    }
}

