@page "/"
@inject LocalStorageService Storage
@inject NavigationManager Nav

<PageTitle>Sites - Site Inspector</PageTitle>

<div class="page-header">
    <h2>Construction Sites</h2>
    <button class="btn btn-primary btn-lg" @onclick="() => Nav.NavigateTo("/sites/new")">+ Add Site</button>
</div>

@if (sites == null)
{
    <p class="loading">Loading sites...</p>
}
else if (sites.Count == 0)
{
    <div class="empty-state">
        <p>No sites yet. Add your first construction site to get started.</p>
    </div>
}
else
{
    <div class="card-list">
        @foreach (var site in sites)
        {
            <div class="card" @onclick="() => Nav.NavigateTo($"/sites/{site.Id}/inspections")">
                <h3>@site.Name</h3>
                <p class="card-subtitle">@site.Address</p>
            </div>
        }
    </div>
}

@code {
    private List<ConstructionSite>? sites;

    protected override async Task OnInitializedAsync()
    {
        await Storage.InitializeAsync();
        sites = await Storage.GetSitesAsync();
    }
}

@page "/sites/new"
@inject LocalStorageService Storage
@inject NavigationManager Nav

<PageTitle>New Site - Site Inspector</PageTitle>

<div class="page-header">
    <h2>New Construction Site</h2>
</div>

<div class="form-container">
    <div class="form-group">
        <label for="name">Site Name</label>
        <input id="name" type="text" class="form-input" @bind="name" placeholder="e.g. Downtown Tower Project" />
    </div>

    <div class="form-group">
        <label for="address">Address</label>
        <input id="address" type="text" class="form-input" @bind="address" placeholder="e.g. 123 Main St, City" />
    </div>

    <div class="form-actions">
        <button class="btn btn-secondary" @onclick="Cancel">Cancel</button>
        <button class="btn btn-primary" @onclick="Save" disabled="@string.IsNullOrWhiteSpace(name)">Save Site</button>
    </div>
</div>

@code {
    private string name = string.Empty;
    private string address = string.Empty;

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(name)) return;

        var site = new ConstructionSite
        {
            Name = name.Trim(),
            Address = address.Trim()
        };

        await Storage.SaveSiteAsync(site);
        Nav.NavigateTo("/");
    }

    private void Cancel() => Nav.NavigateTo("/");
}

