                  @bind:after="SaveInspection" placeholder="Overall inspection notes..."></textarea>
    </div>

    <div class="section">
        <button class="btn btn-secondary btn-lg full-width" @onclick="() => OpenPhotoCapture(null)">
            📷 Add General Photo
        </button>
        @{
            var generalPhotos = photos.Where(p => p.ChecklistItemId == null).ToList();
        }
        @if (generalPhotos.Any())
        {
            <div class="photo-thumbnails" style="margin-top:0.5rem">
                @foreach (var photo in generalPhotos)
                {
                    <img src="data:image/jpeg;base64,@photo.Base64Data" class="thumbnail" alt="@photo.FileName" />
                }
