        checklistItems = await Storage.GetChecklistItemsAsync(InspectionId);
        photos = await Storage.GetPhotosForInspectionAsync(InspectionId);
    }

    private async Task SetStatus(ChecklistItem item, ChecklistStatus status)
    {
        item.Status = status;
        await Storage.SaveChecklistItemAsync(item);
    }

    private async Task SaveChecklistItem(ChecklistItem item)
    {
        await Storage.SaveChecklistItemAsync(item);
    }

    private async Task SaveInspection()
    {
        if (inspection != null)
            await Storage.SaveInspectionAsync(inspection);
    }

    private void ToggleNotes(string itemId)
    {
        if (!expandedNotes.Remove(itemId))
            expandedNotes.Add(itemId);
    }

    private void OpenPhotoCapture(string? checklistItemId)
    {
        currentPhotoItemId = checklistItemId;
        photoPreview = null;
        showPhotoCapture = true;
    }

    private void ClosePhotoCapture()
    {
        showPhotoCapture = false;
        photoPreview = null;
    }

    private async Task OnPhotoSelected(InputFileChangeEventArgs e)
    {
        var file = e.File;
        if (file == null) return;

        var buffer = new byte[file.Size];
        await file.OpenReadStream(maxAllowedSize: 10 * 1024 * 1024).ReadAsync(buffer);
        var base64 = Convert.ToBase64String(buffer);

        photoPreview = $"data:{file.ContentType};base64,{base64}";

        var photo = new InspectionPhoto
        {
            InspectionId = InspectionId,
            ChecklistItemId = currentPhotoItemId,
            FileName = file.Name,
            Base64Data = base64,
            CapturedAt = DateTime.UtcNow
        };

        await Storage.SavePhotoAsync(photo);
        photos.Add(photo);
        showPhotoCapture = false;
        photoPreview = null;
    }

    private async Task CompleteInspection()
    {
        if (inspection != null)
        {
            inspection.CompletedAt = DateTime.UtcNow;
            await Storage.SaveInspectionAsync(inspection);
        }
    }

    private void GoBack()
    {
        if (inspection != null)
            Nav.NavigateTo($"/sites/{inspection.SiteId}/inspections");
        else
            Nav.NavigateTo("/");
    }
}

