+                    <p class="card-meta">✓ Completed</p>
+                }
+                else
+                {
+                    <p class="card-meta in-progress">● In Progress</p>
+                }
+            </div>
+        }
+    </div>
+}
+
+<div class="form-actions" style="margin-top:1rem">
