+
+@code {
+    [Parameter] public string SiteId { get; set; } = string.Empty;
+
+    private ConstructionSite? site;
+    private List<Inspection>? inspections;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await Storage.InitializeAsync();
+        site = await Storage.GetSiteAsync(SiteId);
+        inspections = await Storage.GetInspectionsForSiteAsync(SiteId);
+    }
+
+    private async Task StartNewInspection()
+    {
+        var inspection = new Inspection
+        {
+            SiteId = SiteId,
+            StartedAt = DateTime.UtcNow
+        };
+        await Storage.SaveInspectionAsync(inspection);
+        await CreateDefaultChecklistItems(inspection.Id);
+        Nav.NavigateTo($"/inspections/{inspection.Id}");
+    }
+
+    private async Task CreateDefaultChecklistItems(string inspectionId)
+    {
+        var categories = new Dictionary<string, string[]>
+        {
+            ["Scaffolding & Fall Protection"] = new[]
