+                "Guardrails installed and secure",
+                "Scaffold planks in good condition",
+                "Fall arrest systems available",
+                "Ladder access points secured",
+                "Toe boards in place"
+            },
+            ["Electrical Safety"] = new[]
+            {
+                "GFCI protection on all outlets",
+                "No exposed wiring",
+                "Electrical panels accessible",
+                "Extension cords in good condition",
+                "Lockout/tagout procedures posted"
+            },
+            ["Fire Safety"] = new[]
+            {
+                "Fire extinguishers accessible",
+                "Hot work permits current",
+                "Flammable storage proper",
+                "Emergency exits clear",
+                "Fire watch posted when required"
+            },
+            ["PPE Compliance"] = new[]
+            {
+                "Hard hats worn in designated areas",
+                "Safety glasses/goggles available",
+                "High-visibility vests worn",
+                "Steel-toed boots required",
+                "Hearing protection where needed"
+            },
+            ["Housekeeping"] = new[]
+            {
+                "Work areas clean and organized",
+                "Debris removed regularly",
+                "Walking paths clear",
+                "Materials stored properly",
+                "Waste containers available"
+            },
+            ["Excavation Safety"] = new[]
+            {
+                "Excavations properly shored",
+                "Spoil piles away from edge",
+                "Access/egress provided",
+                "Underground utilities marked",
+                "Daily inspections documented"
+            }
+        };
+
+        foreach (var (category, items) in categories)
+        {
+            foreach (var description in items)
+            {
+                var item = new ChecklistItem
+                {
+                    InspectionId = inspectionId,
+                    Category = category,
+                    Description = description
+                };
+                await Storage.SaveChecklistItemAsync(item);
+            }
+        }
+    }
+
+    private string GetSyncClass(SyncStatus status) => status switch
+    {
+        SyncStatus.Synced => "synced",
+        SyncStatus.Failed => "failed",
+        _ => "pending"
+    };
+
+    private string GetSyncLabel(SyncStatus status) => status switch
+    {
+        SyncStatus.Synced => "✓ Synced",
+        SyncStatus.Failed => "✗ Failed",
+        _ => "⏳ Pending"
+    };
+}
