+        }
+    </div>
+
+    <div class="form-group">
+        <label for="inspector">Inspector Name</label>
+        <input id="inspector" type="text" class="form-input" @bind="inspection.InspectorName"
+               @bind:after="SaveInspection" placeholder="Your name" />
+    </div>
+
+    @foreach (var category in checklistItems.GroupBy(i => i.Category))
+    {
+        <div class="checklist-category">
+            <h3 class="category-title">@category.Key</h3>
+            @foreach (var item in category)
+            {
+                <div class="checklist-item">
+                    <div class="checklist-item-header">
+                        <span class="item-description">@item.Description</span>
+                        <div class="status-buttons">
+                            <button class="status-btn pass @(item.Status == ChecklistStatus.Pass ? "active" : "")"
+                                    @onclick="() => SetStatus(item, ChecklistStatus.Pass)">✓</button>
+                            <button class="status-btn fail @(item.Status == ChecklistStatus.Fail ? "active" : "")"
+                                    @onclick="() => SetStatus(item, ChecklistStatus.Fail)">✗</button>
+                            <button class="status-btn na @(item.Status == ChecklistStatus.NA ? "active" : "")"
+                                    @onclick="() => SetStatus(item, ChecklistStatus.NA)">N/A</button>
+                        </div>
+                    </div>
+                    <div class="checklist-item-actions">
+                        @if (expandedNotes.Contains(item.Id))
+                        {
+                            <textarea class="form-input item-notes" @bind="item.Notes"
+                                      @bind:after="() => SaveChecklistItem(item)"
+                                      placeholder="Add notes..."></textarea>
+                        }
+                        <button class="btn-icon" @onclick="() => ToggleNotes(item.Id)">
+                            📝 @(expandedNotes.Contains(item.Id) ? "Hide" : "Notes")
+                        </button>
+                        <button class="btn-icon" @onclick="() => OpenPhotoCapture(item.Id)">
+                            📷 Photo
+                        </button>
+                    </div>
+                    @{
+                        var itemPhotos = photos.Where(p => p.ChecklistItemId == item.Id).ToList();
+                    }
+                    @if (itemPhotos.Any())
+                    {
+                        <div class="photo-thumbnails">
+                            @foreach (var photo in itemPhotos)
+                            {
+                                <img src="data:image/jpeg;base64,@photo.Base64Data" class="thumbnail" alt="@photo.FileName" />
+                            }
+                        </div>
+                    }
+                </div>
+            }
+        </div>
+    }
+
+    <div class="section general-notes">
+        <h3>General Notes</h3>
+        <textarea class="form-input" rows="4" @bind="inspection.Notes"
+                  @bind:after="SaveInspection" placeholder="Overall inspection notes..."></textarea>
+    </div>
+
+    <div class="section">
+        <button class="btn btn-secondary btn-lg full-width" @onclick="() => OpenPhotoCapture(null)">
+            📷 Add General Photo
+        </button>
+        @{
+            var generalPhotos = photos.Where(p => p.ChecklistItemId == null).ToList();
+        }
+        @if (generalPhotos.Any())
+        {
+            <div class="photo-thumbnails" style="margin-top:0.5rem">
+                @foreach (var photo in generalPhotos)
+                {
+                    <img src="data:image/jpeg;base64,@photo.Base64Data" class="thumbnail" alt="@photo.FileName" />
+                }
+            </div>
+        }
+    </div>
+
+    @if (!inspection.CompletedAt.HasValue)
+    {
+        <div class="form-actions">
+            <button class="btn btn-primary btn-lg full-width" @onclick="CompleteInspection">
+                ✓ Complete Inspection
+            </button>
+        </div>
+    }
+
+    <div class="form-actions">
+        <button class="btn btn-secondary" @onclick="GoBack">← Back</button>
+    </div>
+
+    @if (showPhotoCapture)
+    {
+        <div class="modal-overlay" @onclick="ClosePhotoCapture">
+            <div class="modal-content" @onclick:stopPropagation="true">
+                <h3>Capture Photo</h3>
+                <InputFile OnChange="OnPhotoSelected" accept="image/*" capture="environment" />
+                @if (!string.IsNullOrEmpty(photoPreview))
+                {
+                    <img src="@photoPreview" class="photo-preview" alt="Preview" />
+                }
+                <div class="form-actions">
+                    <button class="btn btn-secondary" @onclick="ClosePhotoCapture">Close</button>
+                </div>
+            </div>
+        </div>
+    }
+}
